pair<int,int> slope_key(pair<int,int> p, pair<int,int> q) {
    int dx = q.first - p.first;
    int dy = q.second - p.second;
    if (dx == 0) return {0, 1};
    if (dy == 0) return {1, 0};
    int g = gcd(dx, dy);
    dx /= g; dy /= g;
    if (dx < 0) { dx = -dx; dy = -dy; }
    return {dx, dy};
}

